prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?init ?initName ?task ?taskName ?choreo WHERE {
  ?model a bboExt:Model ;
         tai:originalId "4e8df28e6d9f4afe970d06522542e830" .
  ?model tai:belongsTo ?org .
  ?model tai:belongsTo ?parentOrg .
  ?defs tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?defs .

  ?init a bboExt:StartEvent ;
        tai:belongsTo ?choreo ;
        bbo:name ?initName .

  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo ;
        bbo:name ?taskName .
  FILTER(CONTAINS(LCASE(STR(?taskName)), LCASE("Buch in aWrenkorb")))

  FILTER EXISTS {
    ?init ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?task .
  }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?task ?taskName ?choreo ?modelId WHERE {
  ?model a bboExt:Model ;
         tai:originalId "4e8df28e6d9f4afe970d06522542e830" ;
         tai:belongsTo ?org .
  ?defs tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?defs .

  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo ;
        bbo:name ?taskName .

  FILTER(CONTAINS(LCASE(STR(?taskName)), LCASE("Buch in aWrenkorb")))

  BIND(?model AS ?modelId)
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?init ?initName ?task ?taskName ?choreo WHERE {
  ?model a bboExt:Model ;
         tai:originalId "4e8df28e6d9f4afe970d06522542e830" .
  ?defs tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ; tai:belongsTo ?defs .

  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo ;
        bbo:name ?taskName .
  FILTER(STR(?taskName) = "Buch in Warenkorb")

  ?init a bboExt:StartEvent ;
        tai:belongsTo ?choreo ;
        bbo:name ?initName .

  FILTER EXISTS {
    ?init ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?task .
  }
}
LIMIT 25
